   949→  /**
   950→   * Validate attribute matrix completeness
   951→   *
   952→   * Checks that all attributes referenced in bonus maps and relevance matrices
   953→   * are actually defined in the attributes schema.
   954→   *
   955→   * @param config - Category configuration to check
   956→   * @returns Array of validation errors for undefined attributes
   957→   */
   958→  validateAttributeMatrix(config: CategoryConfiguration): ValidationError[] {
   959→    const errors: ValidationError[] = [];
   960→
   961→    // Skip if attributes are not defined
   962→    if (!config.processingConfig?.attributes?.schema) {
   963→      return errors;
   964→    }
   965→
   966→    const definedAttributes = new Set(Object.keys(config.processingConfig.attributes.schema));
   967→
   968→    // Check that all attributes in bonus map are defined in schema
   969→    if (config.processingConfig.attributes.attributeBonusMap) {
   970→      for (const [categoryName, bonusMap] of Object.entries(config.processingConfig.attributes.attributeBonusMap)) {
   971→        for (const attributeName of Object.keys(bonusMap)) {
   972→          if (!definedAttributes.has(attributeName)) {
   973→            errors.push({
   974→              code: 'UNDEFINED_ATTRIBUTE',
   975→              message: `Attribute "${attributeName}" used in ${categoryName} bonus map but not defined in schema`,
   976→              path: `attributes.attributeBonusMap.${categoryName}.${attributeName}`,
   977→              severity: 'error',
   978→              category: 'reference',
   979→              suggestion: `Add "${attributeName}" to attributes.schema or remove from bonus map`,
   980→            });
   981→          }
   982→        }
   983→      }
   984→    }
   985→
   986→    // Check attribute relevance matrix completeness
   987→    if (config.processingConfig.attributeRelevance) {
   988→      for (const [categoryName, relevance] of Object.entries(config.processingConfig.attributeRelevance)) {
   989→        if (categoryName === 'RolesLegend') continue;
   990→
   991→        const categoryRoles = (relevance as { categoryRoles?: Record<string, string> }).categoryRoles;
   992→        if (categoryRoles) {
   993→          for (const attributeName of Object.keys(categoryRoles)) {
   994→            if (!definedAttributes.has(attributeName)) {
   995→              errors.push({
   996→                code: 'UNDEFINED_ATTRIBUTE',
   997→                message: `Attribute "${attributeName}" used in ${categoryName} relevance matrix but not defined in schema`,
   998→                path: `attributeRelevance.${categoryName}.categoryRoles.${attributeName}`,
   999→                severity: 'error',
  1000→                category: 'reference',
  1001→                suggestion: `Add "${attributeName}" to attributes.schema or remove from relevance matrix`,
  1002→              });
  1003→            }
  1004→          }
  1005→        }
